","new_string":"    private suspend fun updateCardState(siteId: Long, cardType: CardType, enabled: Boolean) {
        val currentCards: MutableList<DashboardCardState> = _uiState.value?.toMutableList()
            ?: run {
                _uiState.postValue(getCardStates(siteId))
                return
            }

        val index = currentCards.indexOfFirst { it.cardType == cardType }
        if (index == -1) {
            // The expected card might not be present due to feature/eligibility changes.
            // Rebuild the list to avoid crashes and keep UI state in sync with current rules.
            _uiState.postValue(getCardStates(siteId))
            return
        }

        currentCards[index] = currentCards[index].copy(enabled = enabled)
        _uiState.postValue(currentCards)
    }
"}

